import {
  html,
  customElement,
  LitElement,
  when,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbWorkspaceViewElement } from "@umbraco-cms/backoffice/workspace";
import { UmbElementMixin } from "@umbraco-cms/backoffice/element-api";
import type { UmbCollectionConfiguration } from "@umbraco-cms/backoffice/collection";
import { FORMS_FORM_ENTRY_COLLECTION_ALIAS } from "../../../entries/collection/manifests.js";
import { FORMS_FORM_WORKSPACE_CONTEXT } from "../../form-workspace.context-token.js";

const elementName = "workspace-view-form-entries";

@customElement(elementName)
export class UmbWorkspaceViewFormEntriesElement
  extends UmbElementMixin(LitElement)
  implements UmbWorkspaceViewElement
{

  #workspaceContext?: typeof FORMS_FORM_WORKSPACE_CONTEXT.TYPE;

  #config: UmbCollectionConfiguration = {
    pageSize: 10,
  };

  constructor() {
    super();

    this.consumeContext(FORMS_FORM_WORKSPACE_CONTEXT, (instance) => {
      this.#workspaceContext = instance;
    });
  }

  render() {
    return html`
      ${when(!this.#workspaceContext?.getIsNew(),
        () => html`<umb-collection
        alias=${FORMS_FORM_ENTRY_COLLECTION_ALIAS}
        .config=${this.#config}
      ></umb-collection>`)}`;
  }
}

export default UmbWorkspaceViewFormEntriesElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: UmbWorkspaceViewFormEntriesElement;
  }
}
